mapper.select:

select * from t_admin
WHERE 1=1

	 AND adminName = #{adminName,jdbcType=VARCHAR} 


	 AND adminDate >= #{sdate,jdbcType=TIMESTAMP} 


	 AND adminDate <= #{edate,jdbcType=TIMESTAMP} 


	 AND adminDate1 >= #{sdate1,jdbcType=TIMESTAMP} 


	 AND adminDate1 <= #{edate1,jdbcType=TIMESTAMP} 


	
		 AND adminName LIKE  '%${admin.adminName}%' 
	
	
		 AND adminXingming LIKE  '%${admin.adminXingming}%' 
	
	
		 AND adminPassword = #{admin.adminPassword} 
	
	
		 AND adminPhone LIKE  '%${admin.adminPhone}%' 
	
	
		 AND adminId = #{admin.adminId} 
	
	
		 AND adminType = #{admin.adminType} 
	
	
		 AND adminType1 = #{admin.adminType1} 
	
	
		 AND adminType2 = #{admin.adminType2} 
	
	
		 AND adminSex = #{admin.adminSex} 
	

order by adminId desc 

	limit #{page},#{rows}
